#include<bits/stdc++.h>
using namespace std;
int x[2000010],fa[2000010],y[2000010],a[2000010],flag[2000010];
vector<int> mp[2000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
int cnt;
void merge(int x,int y)
{
    int a=find(x),b=find(y);
    if(a!=b)
    {
        cnt--;
        fa[a]=b;
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    cnt=0;
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
        x[i]++;
        y[i]++;
        mp[x[i]].push_back(y[i]);
        mp[y[i]].push_back(x[i]);
    }
    int k;
    scanf("%d",&k);
    for(int i=1;i<=k;i++)
    {
        scanf("%d",&a[i]);
        a[i]++;
        flag[a[i]]=1;
    }
    cnt=n-k;
    for(int i=1;i<=m;i++)
    {
        if(!flag[x[i]]&&!flag[y[i]])
        {
            merge(x[i],y[i]);
        }
    }
    vector<int> ans;
    ans.push_back(cnt);
    for(int i=k;i>=1;i--)
    {
        flag[a[i]]=0;
        cnt++;
        for(int j:mp[a[i]])
        {
            if(!flag[j])
            {
                merge(a[i],j);
            }
        }
        ans.push_back(cnt);
    }
    reverse(ans.begin(),ans.end());
    for(int i:ans)
    {
        printf("%d\n",i);
    }
    return 0;
}
